package com.comp2154.student_system.controller;
import com.comp2154.student_system.model.Course; import com.comp2154.student_system.service.CourseService; import jakarta.validation.Valid; import java.util.*; import org.springframework.http.*; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/courses")
public class CourseController { private final CourseService service; public CourseController(CourseService service){this.service=service;} @GetMapping public List<Course> getAllCourses(){return service.getAllCourses();} @GetMapping("/{id}") public Course getCourseById(@PathVariable Long id){return service.getCourseById(id);} @PostMapping public ResponseEntity<Course> createCourse(@Valid @RequestBody Course c){ return ResponseEntity.status(HttpStatus.CREATED).body(service.createCourse(c)); } @PutMapping("/{id}") public Course updateCourse(@PathVariable Long id,@Valid @RequestBody Course c){ return service.updateCourse(id,c);} @DeleteMapping("/{id}") public Map<String,String> deleteCourse(@PathVariable Long id){ service.deleteCourse(id); return Map.of("message","Course deleted successfully"); } }
